#!/usr/bin/env python3
"""Apply script v4: MFL history-chain discovery.

MFL stores a history chain in the TYPE=league response that maps every
prior season to its league ID and server. One API call resolves the
entire league history automatically — no manual research needed.

Cumulative — includes all changes from v1-v3 plus:
  - discovery.py: _extract_league_history(), discover_mfl_league_via_history()
  - historical_ingest.py: mfl_league_id param (API ID != storage ID)
  - CLI runners: --use-history-chain flag
  - 56 tests

One-command full historical ingest:
  ./scripts/py -u src/squadvault/mfl/_run_historical_ingest.py \\
    --db .local_squadvault.sqlite --league-id 70985 --use-history-chain

Run: python3 apply_mfl_history_chain_v4.py
Then: PYTHONPATH=src python -m pytest Tests/ -q
"""

import base64
from pathlib import Path

